if (! function_exists('file_patch')) {
    function file_patch($content, $operation, $start_line, $end_line = null, $new_lines = null)
    {
        $lines = preg_split('/\r\n|\r|\n/', $content);
        $totalLines = count($lines);
        $op = $operation;
        $start = (int)$start_line;
        $end = isset($end_line) ? (int)$end_line : $start;
        $new = isset($new_lines) && is_array($new_lines) ? $new_lines : [];

        // Validate
        if ($start < 1) {
            return json_encode(['error' => 'start_line must be >= 1', 'original_lines' => $totalLines]);
        }
        if ($end < $start) {
