        }
        if (in_array($op, ['replace', 'delete']) && $end > $totalLines) {
            return json_encode(['error' => "end_line ($end) exceeds total lines ($totalLines)", 'original_lines' => $totalLines]);
        }
        if ($op === 'insert' && $start > $totalLines + 1) {
            return json_encode(['error' => "insert position ($start) exceeds total lines + 1 ($totalLines)", 'original_lines' => $totalLines]);
        }

        switch ($op) {
            case 'replace':
                // Replace lines start..end with new_lines
                $before = array_slice($lines, 0, $start - 1);
                $after = array_slice($lines, $end);
                $patched = array_merge($before, $new, $after);
